-- Useful views for charting

CREATE OR REPLACE VIEW v_dementia_by_sex AS
SELECT year, men, women, persons
FROM dementia_prevalence
ORDER BY year;

CREATE OR REPLACE VIEW v_dementia_by_age AS
SELECT year, age_30_64, age_65_84, age_85_plus
FROM dementia_prevalence
ORDER BY year;
